import{_ as t,o as a,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"91. Backfill","description":"","frontmatter":{"title":"91. Backfill","eba":"Allied Health Professionals 2021-2026","topics":["preliminary","staffing","workload","wages","higher-duties"]},"headers":[],"relativePath":"ebas/allied-health/classification-staffing/91-backfill.md","filePath":"ebas/allied-health/classification-staffing/91-backfill.md"}'),o={name:"ebas/allied-health/classification-staffing/91-backfill.md"};function i(r,e,l,p,c,h){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_91-backfill" tabindex="-1">91. Backfill <a class="header-anchor" href="#_91-backfill" aria-label="Permalink to &quot;91. Backfill&quot;">​</a></h1><p><strong>91.1</strong> Purpose In order to maintain safe staffing, workload levels and appropriate clinical standards, the Employer will Backfill an Absence or, where that is not possible, prioritise work in accordance with this clause 91.</p><p><strong>91.2</strong> Definitions In this clause 91:</p><p><strong>(a)</strong> Backfill means the replacement of an absent Employee with an Employee classified at the same classification and time fraction, save that where this is not possible Backfill means utilising:</p><p><strong>(i)</strong> higher duties to replace the absent Employee with an Employee at a lower classification and/or time fraction to work at and be paid at the higher classification and/or time fraction; and</p><p><strong>(ii)</strong> an Employee classified at a higher grade/class/level than the absent Employee, with the replacement Employee’s paid at their higher rate.</p><p><strong>(b)</strong> Absence includes any type of leave approved by the Employer, WorkCover, absence caused by the resignation or termination of an Employee or an absence due to an Employee being on secondment, either separately or in combination.</p><p><strong>(c)</strong> Planned Absence is any Absence of an Employee where it is known in advance it will be for at least two (2) calendar weeks.</p><p><strong>(d)</strong> Unplanned Absence is any Absence of an Employee, where the Absence was not known in advance. Examples of an Unplanned Absence may include personal leave, resignation without notice or termination of employment resulting in a vacancy or late approved leave.</p><p><strong>91.3</strong> Replacement of staff on Planned Absence</p><p><strong>(a)</strong> The Employer will Backfill a Planned Absence from the first day of the absence except as provided at subclause 91.3(b) below.</p><p><strong>(b)</strong> Where, despite all endeavours, the Employer is unable to Backfill a Planned Absence because a suitably experienced and qualified Employee is unavailable the work will be prioritised under subclause 91.6 below.</p><p><strong>91.4</strong> Unplanned Absences</p><p><strong>(a)</strong> Absences of at least two (2) weeks</p><p><strong>(i)</strong> The Employer will Backfill an Unplanned Absence of at least two (2) calendar weeks.</p><p><strong>(ii)</strong> Where, despite best endeavours, the Employer is unable to Backfill an Unplanned Absence because a suitably experienced and qualified Employee is unavailable, the work will be prioritised under subclause 91.6 below.</p><p><strong>(b)</strong> Absences of less than two (2) weeks</p><p><strong>(i)</strong> The Employer may choose to Backfill an Unplanned Absence of less than two (2) calendar weeks.</p><p><strong>(ii)</strong> When Backfill of an Unplanned Absence of less than two (2) calendar weeks does not occur the Employer will still apply subclauses 91.6 below, save that subclause 91.6(b) does not apply. There is no obligation to apply any other provisions of this clause 91 for an Unplanned Absence of less than two (2) calendar weeks under this subclause 91.4(b).</p><p><strong>91.5</strong> Backfill with existing staff where reasonable The Employer will Backfill by offering existing part-time and, where necessary, casual Employees (which may include bank staff) additional shifts in the first instance.</p><p><strong>91.6</strong> Non-backfilled absences – Work prioritisation</p><p><strong>(a)</strong> Where the Employer is unable to Backfill either a Planned or Unplanned Absence, the Employer will immediately prioritise work to ensure:</p><p><strong>(i)</strong> workloads for other Employees who may be asked to perform the duties of the absent Employee are adjusted by reducing their usual duties;</p><p><strong>(ii)</strong> the work of the absent Employee is not required to be undertaken by any Employee; and</p><p><strong>(iii)</strong> other Employees will not unreasonably be required to work overtime to complete their own work and the work of the absent Employee.</p><p><strong>(b)</strong> Prioritised work arrangements made under subclause 91.6(a) shall be provided in writing to Employees in the service/department of the absent Employee and available for inspection by the Union upon request.</p><p><strong>(c)</strong> Nothing in this clause 91 prevents Employers taking other additional measures consistent with this Agreement to manage or prioritise work where Backfill is not available.</p><p><strong>(d)</strong> If overtime is worked, the provisions of <a href="/eba/ebas/allied-health/hours-of-work/52-overtime.html">clause 52</a> – Overtime will apply.</p><p><strong>(e)</strong> Where possible Employers will employ adequate relief Employees, or obtain an appropriate replacement from the Public Health Sector Relief Bank or equivalent (see subclause 91.8 below).</p><p><strong>(f)</strong> An absent Employee will, on return to work, receive appropriate support to enable them to complete work not done in their absence and is still required to be done.</p><p><strong>91.7</strong> Relevant Information</p><p><strong>(a)</strong> The matters in this clause 91 are directly relevant to workload and the Employer will provide information to the WIC as required by subclause 83.2 of this Agreement.</p><p><strong>(b)</strong> In the event that a WIC has not been established and there is a dispute with respect to this clause 91 the Employer will provide relevant information that will provide clarification of the workload or staffing issues. Information that could be relevant includes workload reviews undertaken in accordance with subclause 90.6</p><p><strong>(c)</strong> On the request of the Union, the Employer will provide in writing details of their attempts to Backfill in accordance with this clause 91.</p><p><strong>91.8</strong> Staffing and Banks</p><p><strong>(a)</strong> Employers recognise adequate relief staff may be needed, or appropriate staff from public health sector relief bank/s utilised in the event they are established, to Backfill in accordance with this clause 91, other than in circumstances where existing Employees (part-time and casual) are offered and accept additional hours/shifts for this purpose.</p><p><strong>(b)</strong> Where an Employer is unable to Backfill Absences in accordance with this clause 91 on a regular basis, the Employer will:</p><p><strong>(i)</strong> consult with affected Employee/s and the Union on this; and</p><p><strong>(ii)</strong> where appropriate, take steps to address the issue.</p><p><strong>(c)</strong> Employers (including through the VHIA) and the Union will discuss in the WIC and BPECC arrangements for building increased relief staff size, which could include sector-wide or internal relief bank/s.</p><p><strong>91.9</strong> Dispute Settlement In the event of a dispute arising over the provisions of this clause 91, either party may choose to have the dispute resolved under the:</p><p><strong>(i)</strong> Dispute Resolution Procedure in this Agreement (<a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a>); or</p><p><strong>(ii)</strong> Independent Dispute Resolution Panel (<a href="/eba/ebas/allied-health/consultation-disputes/14A-independent-dispute-resolution-panel.html">clause 14A</a>).</p>',43)])])}const u=t(o,[["render",i]]);export{f as __pageData,u as default};
